#include <iostream>
#include <string>
#include <sstream>
#include <iomanip>

class ComplexNumber {
private:
    double real;
    double imaginary;

public:
    ComplexNumber(double r = 0.0, double i = 0.0) : real(r), imaginary(i) {}

    double getReal() const { return real; }
    double getImaginary() const { return imaginary; }

    friend ComplexNumber operator+(const ComplexNumber& lhs, const ComplexNumber& rhs);
    friend std::ostream& operator<<(std::ostream& os, const ComplexNumber& c);
};

ComplexNumber operator+(const ComplexNumber& lhs, const ComplexNumber& rhs) {
    return ComplexNumber(lhs.real + rhs.real, lhs.imaginary + rhs.imaginary);
}

std::ostream& operator<<(std::ostream& os, const ComplexNumber& c) {
    os << std::fixed << std::setprecision(2);
    os << c.real;
    if (c.imaginary >= 0) {
        os << " + " << c.imaginary << "i";
    } else {
        os << " - " << -c.imaginary << "i";
    }
    return os;
}

int main() {
    ComplexNumber c1(1.0, 2.0); ComplexNumber c2(3.0, 4.0); ComplexNumber sum1 = c1 + c2; std::cout << sum1 << std::endl;
    ComplexNumber c_t2_1(-0.5, 1.5); ComplexNumber c_t2_2(2.5, -3.5); ComplexNumber sum2 = c_t2_1 + c_t2_2; std::cout << sum2 << std::endl;
    ComplexNumber c_t3_1(1.0, 2.0); ComplexNumber c_t3_2(-0.5, 1.5); ComplexNumber c_t3_3(5.0, 0.0); ComplexNumber sum3 = c_t3_1 + c_t3_2 + c_t3_3; std::cout << sum3 << std::endl;
    ComplexNumber c_t4_1(5.0, 0.0); ComplexNumber c_t4_2(0.0, -7.0); ComplexNumber sum4 = c_t4_1 + c_t4_2; std::cout << sum4 << std::endl;
    return 0;
}
